var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리온…… 너 살아 있어……?","JPN":"リオン……生きてる……？","ENG":"Liona... Are you still alive...?","TWN":"萊恩……你還活著……？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"응……. 도로시 너도 살아 있구나…….","JPN":"うん……ドロシーちゃんも生きてるんだね……","ENG":"Yes... You're alive too...","TWN":"嗯……桃樂絲，你也還活著……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"하암.","JPN":"ふああ。","ENG":"*Yawn*","TWN":"呼哈～"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"놀랐잖아! 기절한 줄 알고!","JPN":"びっくりしたじゃん！　気絶したかと思ったよ！","ENG":"You scared the crap out of me! I thought you fainted!","TWN":"你想嚇死我！我還以為你暈過去咧！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"잠시 꿈 속으로 떠나 있었어. 현실에서도 악몽을 느끼고 싶지는 않아서.","JPN":"ちょっとだけ夢の中に行ってた。現実でも悪夢を感じたくなくて。","ENG":"I made a brief visit to my dreams. I don't want to go through nightmares even in reality.","TWN":"我只是暫時進入夢鄉而已，我不想連在現實世界裡也要經歷惡夢。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"하아…… 하아…….","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼呼……呼呼……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"맙소사, 정말 완주에 성공했어……. 가면도 쓰지 않았는데…….","JPN":"うわあ、本当に完走できた……仮面も被ってないのに……","ENG":"No way... I did it... And I wasn't even wearing my mask...!","TWN":"天啊，真的成功搭完全程咧……而且還是在沒有戴面具的情況下……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그런데 여기는 어디야? 놀이동산인데 아무도 없네?","JPN":"ていうか、ここはどこなんだろう？　遊園地なのに誰もいないね。","ENG":"But where are we? Why's there no one else around?","TWN":"不過這是哪裡？不是遊樂園嗎？怎麼空空的？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"어? 그러게……?","JPN":"え？　そうだね……？","ENG":"Huh? Yeah, that's strange...","TWN":"嗯？對欸……？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"제 생각보다 훨씬 질기군요. 중도 포기가 아무도 없다니요.","JPN":"意外としぶといですね。誰も途中で諦めないとは。","ENG":"You're tougher than you look. I was expecting at least one of you to give up.","TWN":"你們比我想的還有韌性呢，竟然沒人中途說要放棄。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"흥, 잔말 말고 도전장이나 얼른 내놔.","JPN":"ふん、つべこべ言わずに挑戦状をよこしな。","ENG":"Hmph! Shut up and give me the dang ticket already.","TWN":"哼，廢話少說，快把挑戰券交出來！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"도전장 같은 귀찮은 절차는 생략하겠습니다.","JPN":"挑戦状といった面倒くさい手順は省きましょう。","ENG":"We will skip that tedious procedure.","TWN":"我打算省略挑戰券這個麻煩的步驟。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"퍼스트 헤이븐 파크 담당자, 휴스턴입니다.","JPN":"ファーストヘイブンパークの担当者、ヒューストンです。","ENG":"I am Huston, the one in charge of First Haven Park.","TWN":"我是第一天堂主題公園的負責人 休士頓。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"도전 종목은 보물 찾기. 이 놀이공원에 있는 유령의 집 안에서 VIP 카드를 찾으면 됩니다.","JPN":"挑戦種目は宝探し。この遊園地にあるお化け屋敷でVIPカードを探し出せば成功です。","ENG":"My challenge is a treasure hunt. You must enter the haunted mansion and retrieve the VIP card.","TWN":"挑戰內容是尋寶，只要能在遊樂園的鬼屋裡找到VIP卡，卡片就歸你們。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"보물 찾기잖아! 나 잘해!","JPN":"宝探し！　私、それ得意！","ENG":"A treasure hunt! I'm so good at that!","TWN":"尋寶欸！這我超會的！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"보물 찾기라고……?","JPN":"宝探しだって……？","ENG":"A treasure hunt...?","TWN":"尋寶……？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"뭐가 어떻게 돌아가고 있는 거야? 내가 알던 종목은 이게 아닌데?","JPN":"いったい何がどうなってるんだ？　僕の知ってる種目はこれじゃないぞ。","ENG":"What's going on here? This wasn't the game before.","TWN":"怎麼會這樣？這和我知道的內容不一樣？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"내가 모르는 새에 바뀌기라도 한 건가? 아니면 휴스턴이……?","JPN":"僕の知らない間に変わったのか？　それともヒューストンが……？","ENG":"Did they change it without telling me? Or did Huston–","TWN":"是趁我不在時改的嗎？還是休士頓擅自……？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"시간은 정확히 30분 드리죠.","JPN":"時間はぴったり30分差し上げます。","ENG":"You'll have 30 minutes.","TWN":"限時30分鐘。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"건투를 빕니다, 여러분.","JPN":"健闘を祈ります、皆さん。","ENG":"Good luck.","TWN":"那就祝你們好運囉。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};